parameters.jsCode:
const eleve = $input.first().json;
const webhook = $('When Executed by Another Workflow').first().json;
const body = webhook.body;
const meta = body.metadonnees || {};

const timestamp = Date.now();
const random = Math.random().toString(36).substring(2, 8);
const idEmail = 'EMAIL_RAPPEL_' + eleve.id_eleve + '_' + timestamp + '_' + random;

// Calcul du reste à payer
const montantTotal = parseFloat(eleve.montant_total_formation) || parseFloat(meta.montantTotal) || 0;
const montantPaye = parseFloat(eleve.montant_prise_en_charge) || parseFloat(meta.montantPaye) || 0;
const resteAPayer = eleve.reste_a_charge != null
  ? parseFloat(eleve.reste_a_charge)
  : (parseFloat(meta.resteAPayer) || (montantTotal - montantPaye));

const formation = eleve.formation_suivie || meta.formation || 'Formation ABJ';
const modeFinancement = eleve.mode_financement || meta.modeFinancement || '';

const objet = 'Rappel de paiement — ' + formation + ' (Dossier ' + eleve.numero_dossier + ')';

const contenu = 'Bonjour ' + eleve.prenom + ',' +
  '\n\nNous vous contactons au sujet du règlement de votre formation.' +
  '\n\n📋 Récapitulatif de votre dossier :' +
  '\n- Formation : ' + formation +
  '\n- N° Dossier : ' + eleve.numero_dossier +
  '\n- Mode de financement : ' + modeFinancement +
  '\n- Montant total : ' + montantTotal.toLocaleString('fr-FR') + ' €' +
  '\n- Montant réglé : ' + montantPaye.toLocaleString('fr-FR') + ' €' +
  '\n- Reste à payer : ' + resteAPayer.toLocaleString('fr-FR') + ' €' +
  '\n\nNous vous remercions de bien vouloir procéder au règlement du solde restant dans les plus brefs délais.' +
  '\n\nPour toute question, n\'hésitez pas à nous contacter.' +
  '\n\nCordialement,' +
  '\nL\'Académie de Bijouterie Joaillerie';

return [{
  json: {
    id_email: idEmail,
    id_eleve: eleve.id_eleve,
    id_prospect: eleve.id_prospect,
    numero_dossier: eleve.numero_dossier,
    correlation_id: body.correlationId,
    sens: 'sortant',
    email_expediteur: 'contact@academiedebijouteriejoaillerie.fr',
    nom_expediteur: 'ABJ',
    email_destinataire: meta.destinataire || eleve.email,
    objet: objet,
    contenu: contenu,
    montant_total: montantTotal,
    montant_paye: montantPaye,
    reste_a_payer: resteAPayer,
    eleve_nom: eleve.nom,
    eleve_prenom: eleve.prenom
  }
}];

